88	  {
89	    cpu.bind(platform.clk, platform.resetn, platform.reset_vector,
90	             platform.dmi_signals, platform.wfi_signal, platform.int_trigger);
91	
92	    // --- CPU memory BFM → interconnect ---
93	    if constexpr (is_axi) {
94	      mem_bridge = make_axi_to_tlm("mem_bridge", cpu.mem_bfm.isckt);
95	      platform.interconnect.bind_initiator(mem_bridge->tlm_isck);
