130	        slv_bridge = make_tlm_to_axi("slv_bridge", cpu.slv_bfm.tsckt);
131	        platform.interconnect.bind_target(slv_bridge->tlm_tsck,
132	                                          {HART0_ILM_BASE, HART0_DLM_END});
133	      } else {
134	        platform.interconnect.bind_target(cpu.slv_bfm.tsckt,
135	                                          {HART0_ILM_BASE, HART0_DLM_END});
136	      }
