251	      return 0;
252	    }
253	
254	    sim.set_mem_latency(args.mem_latency);
255	
256	    if (!args.ilm_file.empty())
257	      sim.load_image(args.ilm_file, MEM_TYPE::ILM);
258	
259	    if (!args.dlm_file.empty())
260	      sim.load_image(args.dlm_file, MEM_TYPE::DLM);
261	
262	    // End of elaboration
263	    sc_core::sc_start(sc_core::SC_ZERO_TIME);
264	
265	    const auto t0 = std::chrono::steady_clock::now();
266	
267	    if (!args.waveform_file.empty())
268	      sim.enable_waveform(args.waveform_file);
269	
270	    if (!args.pc_trace_file.empty())
271	      sim.enable_pc_trace(args.pc_trace_file);
272	
273	    if (!args.kanata_file.empty() && !args.clarity_file.empty())
274	      throw std::runtime_error("--kanata and --clarity are mutually exclusive");
275	
276	    std::optional<kanata::LoopGate> loop_gate;
277	    if (args.kanata_loop_start.has_value()
278	        != args.kanata_loop_end.has_value())
279	      throw std::runtime_error(
280	        "--kanata-loop-start and --kanata-loop-end must be specified together");
281	    if (args.kanata_loop_start.has_value()) {
282	      if (args.kanata_file.empty() && args.clarity_file.empty())
283	        throw std::runtime_error(
284	          "--kanata-loop-* requires --kanata or --clarity");
285	      if (args.kanata_loop_record == 0)
286	        throw std::runtime_error("--kanata-loop-record must be >= 1");
287	      loop_gate = kanata::LoopGate{*args.kanata_loop_start,
288	                                   *args.kanata_loop_end,
289	                                   args.kanata_loop_skip,
290	                                   args.kanata_loop_record};
291	    }
292	
293	    if (!args.kanata_file.empty())
294	      sim.enable_kanata(args.kanata_file, args.objdump_file, loop_gate);
295	
296	    if (!args.clarity_file.empty())
297	      sim.enable_clarity(args.clarity_file, args.objdump_file, loop_gate);
298	
299	    if (!args.elf_file.empty() && !args.continue_ctx)
300	      sim.load_elf(args.elf_file);
301	
302	    // Apply per-hart reset vector overrides (after load_elf sets defaults)
303	    for (const auto& s: args.reset_vectors) {
304	      auto [hart, addr] = parse_reset_vector(s);
305	      if (hart) {
306	        sim.set_reset_vector(*hart, addr);
307	      } else {
308	        for (size_t i = 0; i < sim.platform.reset_vector.size(); ++i)
309	          sim.set_reset_vector(i, addr);
310	      }
311	    }
312	
313	    if (args.continue_ctx)
314	      spdlog::info("You're resuming program from the given context");
315	
316	    if (args.jtag_port)
317	      sim.init_debug_port(args.jtag_port.value());
318	
319	    if (!args.jtag_port && args.elf_file.empty() && !args.continue_ctx)
320	      throw std::runtime_error("Required arg : program or --jtag-port");
321	
322	    if (args.continue_ctx || args.save_ctx) {
323	      std::string_view s = args.context_dir;
324	      if (std::filesystem::exists(s) && !std::filesystem::is_directory(s))
325	        throw std::runtime_error("Error: Path " + std::string{s}
326	                                 + " exists but is not a directory.");
327	      if (!std::filesystem::exists(s)) {
328	        try {
329	          std::filesystem::create_directories(s);
330	        } catch (const std::filesystem::filesystem_error& e) {
331	          throw std::runtime_error(std::string{"Failed to create directory: "}
332	                                   + e.what());
333	        }
334	      }
335	      sim.context_config = {args.save_ctx, args.continue_ctx, args.context_dir};
336	    }
337	
338	    sim.reset();
339	
340	    const int exit_code = sim.run();
341	
342	    sim.cpu.final();
343	
344	    const auto t1 = std::chrono::steady_clock::now();
345	    const auto cycles = sim.get_cycles();
346	    spdlog::info("{} cycles simulated", cycles);
347	    if (cycles > 0) {
348	      const auto ms =
349	        std::chrono::duration_cast<std::chrono::milliseconds>(t1 - t0);
350	      spdlog::info("{}.{:03}s elapsed, {:.3f}Hz", ms.count() / 1000,
351	                   ms.count() % 1000,
352	                   double(cycles) / double(ms.count()) * 1000.0);
353	    }
354	    return exit_code;
355	  };
356	
357	  return do_sim.operator()<VSIM_CPU_INTERFACE_CLASS>();
358	
359	} catch (const std::exception& e) {
360	  spdlog::critical("fatal exception: {}\n", e.what());
361	  std::exit(EXIT_FAILURE);
362	} catch (...) {
363	  std::terminate();
364	}
