#pragma once

#include "utils/gz_memory.hpp"

#include <spdlog/spdlog.h>
#include <systemc>

#include <cstdint>

#include <string>

#ifdef VSIMSAVABLE
#include <verilated_save.h>
#endif

template<typename CPU>
class ContextManager
{
public:
  bool save_on_wfi = false;
  bool continue_from = false;
  std::string dir = "./saved_ctx/";

  template<typename PLATFORM>
  void restore(PLATFORM& platform, CPU& cpu) const
  {
    load_gz_memory(platform.main_memory.data, dir + "/main_memory");
#ifdef VSIMSAVABLE
    VerilatedRestore os;
    double time;
    os.open(dir + "/context");
    os >> time;
    os >> cpu;
    // TODO: how to restore simulation time?
#else
    (void) cpu;
    spdlog::critical(
      "Context restore not supported (VSIMSAVABLE not compiled)");
#endif
  }

  template<typename PLATFORM>
  void save(PLATFORM& platform, CPU& cpu) const
  {
    dump_gz_memory(platform.main_memory.data, dir + "/main_memory");
#ifdef VSIMSAVABLE
    VerilatedSave os;
    os.open(dir + "/context");
    os << (double) sc_core::sc_time_stamp().value();
    os << cpu;
#else
    (void) cpu;
    spdlog::critical("Context save not supported (VSIMSAVABLE not compiled)");
#endif
  }
};

