#include "pipeview/kanata_logger.hpp"

#define DOCTEST_CONFIG_IMPLEMENT_WITH_MAIN
#include <doctest.h>

#include <sstream>
#include <string>

namespace {

constexpr uint64_t START_PC = 0x100;
constexpr uint64_t END_PC   = 0x118;
constexpr uint64_t OTHER_PC = 0x110;

bool contains(const std::string& haystack, const std::string& needle)
{
  return haystack.find(needle) != std::string::npos;
}

} // namespace

TEST_CASE("no gate: writes pass through unchanged")
{
  std::stringstream ss;
  kanata::KanataLogger log{ss};

  log.start_insn(START_PC, /*id=*/1);
  log.advance_cycle(1);
  log.retire_insn(/*id=*/1);

  const auto out = ss.str();
  CHECK(contains(out, "I\t1\t1\t0"));
  CHECK(contains(out, "L\t1\t0\t0x100"));
  CHECK(contains(out, "C\t1"));
  CHECK(contains(out, "R\t1\t1\t0"));
}

TEST_CASE("gate skip=0: nothing recorded before start_pc fetch")
{
  std::stringstream ss;
  kanata::KanataLogger log{
    ss, kanata::LoopGate{START_PC, END_PC, /*skip=*/0, /*record=*/10}};

  // CRT/init: many insns at OTHER_PC. With skip=0 the doc says "records from
  // the first iteration" — meaning the first iteration of THIS loop, not from
  // cycle 0. The gate must stay closed until start_pc is fetched.
  for (uint64_t id = 1; id <= 5; ++id) {
    log.start_insn(OTHER_PC, id);
    log.advance_cycle(1);
    log.retire_insn(id);
  }

  CHECK(ss.str().find("I\t") == std::string::npos);
  CHECK(ss.str().find("R\t") == std::string::npos);

  // First iteration of the loop body begins now.
  log.start_insn(START_PC, /*id=*/100);
  log.retire_insn(/*id=*/100);
  log.start_insn(END_PC, /*id=*/101);
  log.retire_insn(/*id=*/101);

