// Hybrid simulator (QEMU + Verilator vsim) state-exchange ABI - v1.
//
// This header is the wire contract between the QEMU TCG plugin
// (hybrid/qemu_plugin/) and vsim (src/hybrid/). Both sides write/read
// `struct hybrid_state_v1` byte-for-byte through a shared file.
//
// Stability rule: never repurpose offsets within a published version. Add new
// fields by bumping HYBRID_STATE_VERSION and consuming bytes from `reserved`,
// or by introducing v2 alongside v1.
//
// C and C++ both compile this header. No SystemC, no spdlog, no LIEF.

#ifndef HYBRID_STATE_ABI_H
#define HYBRID_STATE_ABI_H

#include <stdint.h>
#include <stddef.h>

#ifdef __cplusplus
extern "C" {
#endif

// 'AHYB' as the file's first four bytes when read on a little-endian host.
// 'A'=0x41 'H'=0x48 'Y'=0x59 'B'=0x42 -> 0x42594841.
#define HYBRID_STATE_MAGIC   0x42594841u
#define HYBRID_STATE_VERSION 1u

// flags (bitmask)
#define HYBRID_FLAG_RV64 (1u << 0)
#define HYBRID_FLAG_FP   (1u << 1)
#define HYBRID_FLAG_V    (1u << 2)

// V-extension regfile width upper bound. 1024 bits = 128 bytes covers all
// AX45MPV configurations and leaves headroom for future cores.
#define HYBRID_VLEN_BYTES_MAX 128

// Per RISC-V spec: 64 PMP entries, packed into pmpcfg CSRs (8 entries per
// 64-bit pmpcfg on RV64 -> 8 CSRs; we reserve 16 to stay forward-compatible
// with 16-byte packings or RV32 layouts).
#define HYBRID_PMP_CFG_NUM  16
#define HYBRID_PMP_ADDR_NUM 64

// All fields are naturally 8-byte aligned so the layout is trivially packed.
// No __attribute__((packed)) is needed and avoiding it preserves aligned
// loads/stores. The build asserts (state_abi_check.h) lock the layout.
struct hybrid_state_v1 {
  // Header (32 bytes)
  uint32_t magic;     // = HYBRID_STATE_MAGIC
  uint32_t version;   // = HYBRID_STATE_VERSION
  uint32_t flags;     // HYBRID_FLAG_*
  uint32_t hart_id;   // 0-based hart index
  uint64_t pc;        // resume PC
  uint64_t priv;      // privilege mode at handoff (0=U, 1=S, 3=M)

  // Architectural register files
  uint64_t gpr[32];   // x0..x31 (x0 always reads as 0; carried for symmetry)
  uint64_t fpr[32];   // f0..f31 (only valid when HYBRID_FLAG_FP set)

  // M-mode CSRs (selected, read/written via DM Abstract Commands on vsim side)
  uint64_t mstatus;
  uint64_t mepc;
  uint64_t mtvec;
  uint64_t mcause;
  uint64_t mtval;
  uint64_t mscratch;
  uint64_t medeleg;
  uint64_t mideleg;
  uint64_t mip;
  uint64_t mie;
  uint64_t mcycle;
  uint64_t minstret;
  uint64_t satp;

  // PMP
  uint64_t pmpcfg[HYBRID_PMP_CFG_NUM];
  uint64_t pmpaddr[HYBRID_PMP_ADDR_NUM];

  // V-extension scalar state and regfile
  uint64_t vstart;
  uint64_t vtype;
  uint64_t vl;
  uint64_t vlenb;
  uint8_t  vreg[32 * HYBRID_VLEN_BYTES_MAX];

  // Forward-compatibility scratch. Zero-initialise on write.
  uint8_t  reserved[256];
};

#ifdef __cplusplus
}  // extern "C"
#endif

#endif  // HYBRID_STATE_ABI_H

