===FILE: tests/hybrid/state_abi.test.cpp===
// Phase 0.1 RED: ABI contract for hybrid handoff state.
// Locks magic/version constants, struct layout, and byte-level roundtrip.
// state_abi.h does not exist yet -- this file MUST fail to compile until it does.

#include "hybrid/state_abi.h"

#define DOCTEST_CONFIG_IMPLEMENT_WITH_MAIN
#include <doctest.h>

#include <cstdint>
#include <cstring>
#include <type_traits>

TEST_CASE("magic and version are stable wire constants")
{
  // 'AHYB' read little-endian: 'A'=0x41 'H'=0x48 'Y'=0x59 'B'=0x42
  CHECK(HYBRID_STATE_MAGIC == 0x42594841u);
  CHECK(HYBRID_STATE_VERSION == 1u);
}

TEST_CASE("struct is standard-layout, trivially copyable, packed")
{
  CHECK(std::is_standard_layout_v<hybrid_state_v1>);
  CHECK(std::is_trivially_copyable_v<hybrid_state_v1>);
  // packed: fields are 8-byte aligned naturally, so packing should not shrink
  // sizeof. We assert no implicit tail padding either.
  CHECK(sizeof(hybrid_state_v1) % 8 == 0);
}

TEST_CASE("header field offsets")
{
  CHECK(offsetof(hybrid_state_v1, magic) == 0);
  CHECK(offsetof(hybrid_state_v1, version) == 4);
  CHECK(offsetof(hybrid_state_v1, flags) == 8);
  CHECK(offsetof(hybrid_state_v1, hart_id) == 12);
  CHECK(offsetof(hybrid_state_v1, pc) == 16);
  CHECK(offsetof(hybrid_state_v1, priv) == 24);
}

TEST_CASE("GPR and FPR are 32 * uint64_t each, contiguous")
{
  CHECK(offsetof(hybrid_state_v1, gpr) == 32);
  CHECK(sizeof(((hybrid_state_v1*) 0)->gpr) == 32 * sizeof(uint64_t));
  CHECK(offsetof(hybrid_state_v1, fpr) == 32 + 32 * 8);
  CHECK(sizeof(((hybrid_state_v1*) 0)->fpr) == 32 * sizeof(uint64_t));
}

TEST_CASE("V-extension fields use compile-time MAX_VLEN constant")
{
  CHECK(HYBRID_VLEN_BYTES_MAX >= 16);  // RVV minimum VLEN=128 -> 16 bytes
  CHECK((HYBRID_VLEN_BYTES_MAX & (HYBRID_VLEN_BYTES_MAX - 1)) == 0);  // power of 2
  CHECK(sizeof(((hybrid_state_v1*) 0)->vreg) == 32u * HYBRID_VLEN_BYTES_MAX);
}

TEST_CASE("PMP arrays are sized per spec")
{
  CHECK(sizeof(((hybrid_state_v1*) 0)->pmpcfg) == HYBRID_PMP_CFG_NUM * sizeof(uint64_t));
  CHECK(sizeof(((hybrid_state_v1*) 0)->pmpaddr) == HYBRID_PMP_ADDR_NUM * sizeof(uint64_t));
  CHECK(HYBRID_PMP_ADDR_NUM == 64);
  CHECK(HYBRID_PMP_CFG_NUM == 16);
}

TEST_CASE("trailing reserved padding is at least 256 bytes")
{
  CHECK(sizeof(((hybrid_state_v1*) 0)->reserved) >= 256);
}

TEST_CASE("byte-level roundtrip via memcpy preserves all fields")
{
  hybrid_state_v1 src{};
  src.magic = HYBRID_STATE_MAGIC;
  src.version = HYBRID_STATE_VERSION;
  src.flags = HYBRID_FLAG_RV64 | HYBRID_FLAG_FP | HYBRID_FLAG_V;
  src.hart_id = 1;
  src.pc = 0x80001234ULL;
  src.priv = 3;  // M-mode

  for (int i = 0; i < 32; ++i) {
    src.gpr[i] = 0xCAFE0000ULL + i;
    src.fpr[i] = 0xF00D0000ULL + i;
  }
  src.mstatus = 0xa00040080ULL;
  src.mepc    = 0x80002000ULL;
  src.mtvec   = 0x80000000ULL;
  src.satp    = 0x8000000000080000ULL;
  src.vstart  = 0;
  src.vtype   = 0xc0;
  src.vl      = 4;
  src.vlenb   = 16;
  for (size_t i = 0; i < sizeof(src.vreg); ++i) src.vreg[i] = (uint8_t) i;

  alignas(hybrid_state_v1) unsigned char buf[sizeof(hybrid_state_v1)];
  std::memcpy(buf, &src, sizeof(src));
  hybrid_state_v1 dst{};
  std::memcpy(&dst, buf, sizeof(dst));

  CHECK(dst.magic == HYBRID_STATE_MAGIC);
  CHECK(dst.version == HYBRID_STATE_VERSION);
  CHECK(dst.flags == src.flags);
  CHECK(dst.hart_id == 1);
  CHECK(dst.pc == 0x80001234ULL);
  CHECK(dst.priv == 3);
  for (int i = 0; i < 32; ++i) {
    CHECK(dst.gpr[i] == 0xCAFE0000ULL + i);
    CHECK(dst.fpr[i] == 0xF00D0000ULL + i);
  }
  CHECK(dst.mstatus == 0xa00040080ULL);
  CHECK(dst.mepc == 0x80002000ULL);
  CHECK(dst.mtvec == 0x80000000ULL);
  CHECK(dst.satp == 0x8000000000080000ULL);
  CHECK(dst.vtype == 0xc0);
  CHECK(dst.vl == 4);
  CHECK(dst.vlenb == 16);
  CHECK(std::memcmp(dst.vreg, src.vreg, sizeof(src.vreg)) == 0);
}

TEST_CASE("flag bits are stable wire constants")
{
  CHECK(HYBRID_FLAG_RV64 == (1u << 0));
  CHECK(HYBRID_FLAG_FP   == (1u << 1));
  CHECK(HYBRID_FLAG_V    == (1u << 2));
}
===FILE: hybrid/scripts/test_dm_coverage.tcl===
# OpenOCD probe: which RISC-V Debug Module Abstract-Command regnos are reachable
# on the running vsim DM? Phase 0 risk-buster -- if anything we need for the
# hybrid handoff is unreachable here, Phase 5 must add a Program Buffer or DPI
# fallback before Phase 2 ships.
#
# Usage:
#   1. Start vsim with --jtag-port 9104 and the smallest hello.elf.
#   2. openocd -f hybrid/scripts/test_dm_coverage.tcl 2>&1 | tee hybrid/docs/dm_coverage.log
#   3. Translate the log into a tickbox table at hybrid/docs/dm_coverage.md.
#
# Spec ref: RISC-V External Debug Support 1.0, table "Abstract Register Numbers".

# --- vsim DM transport ---------------------------------------------------------
adapter driver remote_bitbang
remote_bitbang_host localhost
remote_bitbang_port 9104

# vsim's DM uses the standard riscv DTM + DM. AX45MPV exposes one hart per core.
set _CHIPNAME riscv
jtag newtap $_CHIPNAME cpu -irlen 5 -expected-id 0x10e31913
set _TARGETNAME $_CHIPNAME.cpu
target create $_TARGETNAME riscv -chain-position $_TARGETNAME

riscv set_command_timeout_sec 5

init
halt

# --- helpers -------------------------------------------------------------------
proc probe_reg {label regno} {
    # 'reg' addresses GPRs/CSRs by symbolic name on OpenOCD; for raw regno we
    # use the abstract command directly via 'riscv dmi_read/write' helpers.
    if {[catch {set v [riscv dm_read $regno]} err]} {
        puts "MISS  $label (regno=[format 0x%04x $regno]) : $err"
        return 0
    } else {
        puts "OK    $label (regno=[format 0x%04x $regno]) = $v"
        return 1
    }
}

# --- coverage matrix -----------------------------------------------------------
puts "=== GPR x0..x31 (regno 0x1000-0x101F) ==="
set gpr_ok 0
for {set i 0} {$i < 32} {incr i} {
    set gpr_ok [expr {$gpr_ok + [probe_reg "x$i" [expr {0x1000 + $i}]]}]
}
puts "GPR reachable: $gpr_ok / 32"

puts "\n=== FPR f0..f31 (regno 0x1020-0x103F) ==="
set fpr_ok 0
for {set i 0} {$i < 32} {incr i} {
    set fpr_ok [expr {$fpr_ok + [probe_reg "f$i" [expr {0x1020 + $i}]]}]
}
puts "FPR reachable: $fpr_ok / 32"

puts "\n=== Standard M-mode CSRs (regno = csr address) ==="
foreach {name addr} {
    mstatus  0x300
    misa     0x301
    medeleg  0x302
    mideleg  0x303
    mie      0x304
    mtvec    0x305
    mscratch 0x340
    mepc     0x341
    mcause   0x342
    mtval    0x343
    mip      0x344
    satp     0x180
    mcycle   0xb00
    minstret 0xb02
} {
    probe_reg $name $addr
}

puts "\n=== PMP (16 cfg + 64 addr CSRs) ==="
for {set i 0} {$i < 16} {incr i} {
    probe_reg "pmpcfg$i"  [expr {0x3a0 + $i}]
}
for {set i 0} {$i < 64} {incr i} {
    probe_reg "pmpaddr$i" [expr {0x3b0 + $i}]
}

puts "\n=== V-extension scalar CSRs ==="
foreach {name addr} {
    vstart 0x008
    vxsat  0x009
    vxrm   0x00a
    vcsr   0x00f
    vl     0xc20
    vtype  0xc21
    vlenb  0xc22
} {
    probe_reg $name $addr
}

puts "\n=== Andes-custom CSRs (sample; full list lives in andes-v5-priv-spec) ==="
foreach {name addr} {
    mmsc_cfg  0xfc2
    mmisc_ctl 0x7d0
    mcache_ctl 0x7ca
    mcctlbeginaddr 0x7cb
    mcctlcommand   0x7cc
    mcctldata      0x7cd
} {
    probe_reg $name $addr
}

puts "\n=== Vector regfile via Abstract Commands? (regno 0x1020 + offset is FPR; ==="
puts "===  V regs typically need Program Buffer load/store - testing scratch. ==="
# RISC-V Debug Spec does not assign abstract regnos to V regs; the path is
# Program Buffer. We only note the absence here; Phase 5 measures the cost.

shutdown
