// Compile-time layout lock for hybrid_state_v1.
//
// Any drift in the offset of a published field, or a size change to an array,
// breaks every translation unit that includes state_abi.h. This is the
// intended behaviour: the ABI is a wire contract.
//
// Adding a NEW field consumes bytes from `reserved`; the existing asserts must
// continue to hold and a new assert is added for the new field.

#ifndef HYBRID_STATE_ABI_CHECK_H
#define HYBRID_STATE_ABI_CHECK_H

#include "hybrid/state_abi.h"

#if defined(__cplusplus)
#  define HYBRID_STATIC_ASSERT(expr, msg) static_assert((expr), msg)
#else
#  define HYBRID_STATIC_ASSERT(expr, msg) _Static_assert((expr), msg)
#endif

// Header
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, magic)   == 0,  "magic@0");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, version) == 4,  "version@4");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, flags)   == 8,  "flags@8");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, hart_id) == 12, "hart_id@12");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, pc)      == 16, "pc@16");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, priv)    == 24, "priv@24");

// Register files
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, gpr) == 32,  "gpr@32");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, fpr) == 288, "fpr@288");

// CSRs (M-mode)
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mstatus)  == 544, "mstatus@544");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mepc)     == 552, "mepc@552");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mtvec)    == 560, "mtvec@560");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mcause)   == 568, "mcause@568");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mtval)    == 576, "mtval@576");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mscratch) == 584, "mscratch@584");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, medeleg)  == 592, "medeleg@592");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mideleg)  == 600, "mideleg@600");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mip)      == 608, "mip@608");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mie)      == 616, "mie@616");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, mcycle)   == 624, "mcycle@624");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, minstret) == 632, "minstret@632");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, satp)     == 640, "satp@640");

// PMP
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, pmpcfg)  == 648, "pmpcfg@648");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, pmpaddr) == 776, "pmpaddr@776");

// V-extension
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, vstart) == 1288, "vstart@1288");
HYBRID_STATIC_ASSERT(offsetof(struct hybrid_state_v1, vtype)  == 1296, "vtype@1296");
