#pragma once

#include "cpu_config.hpp"
#include "platform/memory_map.h"
#include "platform/platform.hpp"
#include "pybind11.hpp"
#include "simulator_context.hpp"
#include "simulator_trace.hpp"
#include "utils/axi.hpp"
#include "utils/axi_to_tlm_bridge.hpp"
#include "utils/elf_loader.hpp"
#include "utils/sizeconvert.hpp"

#include <systemc>
#include <tlm>

#include <csignal>
#include <cstdint>

#include <experimental/scope>
#include <memory>
#include <string>

template<typename CPU>
class Simulator : sc_core::sc_module
{
  using PLATFORM = Platform<platform_config<CPU>>;
  static constexpr bool is_axi = (CPU::SYSTEM_BUS_TYPE == BusTypes::AXI);
  static constexpr auto bus_width = PLATFORM::data_width;

  // Helper: create an AXI→TLM bridge, bind clock, connect initiator BFM
  auto make_axi_to_tlm(const char* name, auto& bfm_socket)
    -> std::unique_ptr<axi_to_tlm_bridge<bus_width>>
  {
    auto bridge = std::make_unique<axi_to_tlm_bridge<bus_width>>(name);
    bridge->pe.clk_i.bind(platform.clk);
    bfm_socket.bind(bridge->axi_tsck);
    return bridge;
  }

  // Helper: create a TLM→AXI bridge, bind clock, connect target BFM
  auto make_tlm_to_axi(const char* name, auto& bfm_socket)
    -> std::unique_ptr<tlm_to_axi_bridge<bus_width>>
  {
    auto bridge = std::make_unique<tlm_to_axi_bridge<bus_width>>(name);
    bridge->pe.clk_i.bind(platform.clk);
    bridge->axi_isck.bind(bfm_socket);
    return bridge;
  }

public:
  CPU cpu;
  PLATFORM platform;

  // AXI bridges (only used when is_axi == true, null otherwise)
  std::unique_ptr<axi_to_tlm_bridge<bus_width>> mem_bridge;
  std::unique_ptr<axi_to_tlm_bridge<bus_width>> mmio_bridge;
  std::unique_ptr<tlm_to_axi_bridge<bus_width>> hvm_bridge;
  std::unique_ptr<tlm_to_axi_bridge<bus_width>> slv_bridge;

  // sys bus (64-bit slave port on CPU, needs width adapter to 256-bit
  // interconnect)
  static constexpr std::size_t sys_bus_width = 64;
  std::unique_ptr<socket_width_adapter<bus_width, sys_bus_width>> sys_adapter;
  std::unique_ptr<tlm_to_axi_bridge<sys_bus_width>> sys_bridge;

#if _NDS_IOCP_NUM > 0
  // iocp_master connects directly to CPU, not through the interconnect.
  // It needs to speak the CPU's bus protocol.
  using IocpInitiatorType = std::
    conditional_t<is_axi, AxiPeInitiator<bus_width>, AhbPeInitiator<bus_width>>;
  IocpInitiatorType iocp_master;
#endif // _NDS_IOCP_NUM

private:
  // debug
  jtag_dtm& dtm;
  bool dtm_debug = false;
  TraceController<CPU> trace_;

  using xlen_t = std::conditional_t<CPU::NDS_XLEN <= 32, uint32_t, uint64_t>;

public:
  ContextManager<CPU> context_config;

  Simulator(const sc_core::sc_module_name& name)
      : sc_core::sc_module{name}, dtm(platform.dtm)
  {
    cpu.bind(platform.clk, platform.resetn, platform.reset_vector,
             platform.dmi_signals, platform.wfi_signal, platform.int_trigger);

    // --- CPU memory BFM → interconnect ---
    if constexpr (is_axi) {
      mem_bridge = make_axi_to_tlm("mem_bridge", cpu.mem_bfm.isckt);
      platform.interconnect.bind_initiator(mem_bridge->tlm_isck);
    } else {
      platform.interconnect.bind_initiator(cpu.mem_bfm.isckt);
    }

    // --- CPU MMIO BFM → interconnect ---

