public:
  static constexpr uint64_t INVALID_ADDRESS = 0xffffffffffffffff;

  const MemoryRegion region;
  const MemoryRegion alias_region;

private:
  std::vector<uint8_t> owned_storage_;

public:
  // `data` aliases either `owned_storage_` (default) or an externally supplied
  // buffer (e.g. an mmap of a shared file). All read/write paths go through
  // this span so the backing choice is invisible to call sites.
  std::span<uint8_t> data;

  unsigned latency = 1;
  tlm_utils::simple_target_socket<SimpleMemory<BusWidth>, BusWidth> socket{
    "tsck"};

  // If `external_buffer` is empty, owned storage is allocated. Otherwise the
  // buffer must outlive this object and be at least as large as the region;
  // hybrid mode passes an mmap of a shared file here.
