TEST_CASE("simple_memory uses externally-supplied buffer when provided")
{
  // Hybrid mode wires shared mmap RAM by handing a span to SimpleMemory.
  // Writes through the TLM socket must land in the external buffer; reads
  // must observe bytes the external owner placed there.
  std::array<uint8_t, 0x100> external{};
  external[0x10] = 0x42;  // sentinel placed by external owner

  SimpleMemory<32> mem{"mem", MemoryRegion{0x1000, 0x10ff},
                       MemoryRegion{SimpleMemory<32>::INVALID_ADDRESS,
                                    SimpleMemory<32>::INVALID_ADDRESS},
                       std::span<uint8_t>{external}};

  CHECK(mem.data.data() == external.data());

  {
    std::array<uint8_t, 1> read_data{};
    tlm::tlm_generic_payload gp;
    gp.set_command(tlm::TLM_READ_COMMAND);
    gp.set_address(0x1010);
    gp.set_data_ptr(read_data.data());
    gp.set_data_length(read_data.size());
    gp.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
    sc_core::sc_time delay = sc_core::SC_ZERO_TIME;
    mem.b_transport(gp, delay);

    CHECK(gp.get_response_status() == tlm::TLM_OK_RESPONSE);
    CHECK(read_data[0] == 0x42);
  }

  {
    std::array<uint8_t, 4> write_data{0xca, 0xfe, 0xba, 0xbe};
    tlm::tlm_generic_payload gp;
    gp.set_command(tlm::TLM_WRITE_COMMAND);
    gp.set_address(0x1020);
    gp.set_data_ptr(write_data.data());
    gp.set_data_length(write_data.size());
    gp.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
    sc_core::sc_time delay = sc_core::SC_ZERO_TIME;
    mem.b_transport(gp, delay);

    CHECK(gp.get_response_status() == tlm::TLM_OK_RESPONSE);
    CHECK(external[0x20] == 0xca);
    CHECK(external[0x21] == 0xfe);
    CHECK(external[0x22] == 0xba);
    CHECK(external[0x23] == 0xbe);
  }
}

