#pragma once

#include "memory_region.hpp"

#include <spdlog/spdlog.h>
#include <systemc>
#include <tlm>
#include <tlm_utils/simple_target_socket.h>

#include <cstdint>
#include <span>
#include <vector>

template<std::size_t BusWidth>
class SimpleMemory : public sc_core::sc_module
{
public:
  static constexpr uint64_t INVALID_ADDRESS = 0xffffffffffffffff;

  const MemoryRegion region;
  const MemoryRegion alias_region;

private:
  std::vector<uint8_t> owned_storage_;

public:
  std::span<uint8_t> data;

  unsigned latency = 1;
  tlm_utils::simple_target_socket<SimpleMemory<BusWidth>, BusWidth> socket{
    "tsck"};

  // If `external_buffer` is empty, owned storage of region size is allocated.
  // Otherwise the buffer must outlive this object and be at least region size;
  // the size mismatch is rejected before any allocation.
  SimpleMemory(const sc_core::sc_module_name& name,
               const MemoryRegion& region,
               const MemoryRegion& alias_region = {INVALID_ADDRESS,
                                                   INVALID_ADDRESS},
               std::span<uint8_t> external_buffer = {})
      : sc_core::sc_module{name},
        region(region),
        alias_region(alias_region),
        owned_storage_(owned_size(external_buffer, region)),
        data(external_buffer.empty() ? std::span<uint8_t>{owned_storage_}
                                     : external_buffer)
  {
    this->socket.register_b_transport(this, &SimpleMemory::b_transport);
  }

  void b_transport(tlm::tlm_generic_payload& trans, sc_core::sc_time& delay)
  {
    auto cycles = handle_trans(trans);
    if (trans.get_response_status() == tlm::TLM_INCOMPLETE_RESPONSE)
      trans.set_response_status(tlm::TLM_OK_RESPONSE);
    delay += sc_core::sc_time(cycles, sc_core::SC_NS);
  }

private:
  static auto owned_size(std::span<uint8_t> external_buffer,
                         const MemoryRegion& region) -> std::size_t
  {
    const auto required = region.end_address - region.base_address;
    if (external_buffer.empty())
      return required;
    if (external_buffer.size() < required) [[unlikely]]
      throw std::runtime_error(
        "SimpleMemory external_buffer smaller than region size");
    return 0;
  }

  auto handle_trans(tlm::tlm_generic_payload& trans) -> unsigned
  {
    const auto addr = trans.get_address();
    const auto len = trans.get_data_length();
    const auto ptr = trans.get_data_ptr();
    const auto byte_enable_len = trans.get_byte_enable_length();
    const auto byte_enable_ptr = trans.get_byte_enable_ptr();

    spdlog::debug("mem: {}, addr={:#x}, len={}",
                  trans.is_read() ? "read" : "write", addr, len);

    uint64_t offset;
    if (region.contains({addr, addr + len})) [[likely]] {
      offset = addr - this->region.base_address;
    } else if (alias_region.contains({addr, addr + len})) {
      offset = addr - this->alias_region.base_address;
    } else {
      spdlog::error(
        "transaction is out of bounds of memory region [{:#x}-{:#x}]",
        this->region.base_address, this->region.end_address);
      trans.set_response_status(tlm::TLM_ADDRESS_ERROR_RESPONSE);
      return latency;
    }
    const auto buf = std::span{ptr, ptr + len};
    if (trans.is_read()) [[likely]] {
      std::copy_n(this->data.begin() + offset, len, buf.begin());
      return latency;
    }

    if (!trans.is_write()) [[unlikely]] {
      throw std::runtime_error("unimplemented");
    }

    if (byte_enable_len == 0) [[likely]] {
      std::copy_n(buf.begin(), len, this->data.begin() + offset);
      return latency;
    }

    // AXI/AHB may split an un-aligned write into multiple aligned writes
    // with a byte-enable mask.
    assert(byte_enable_len == len);
    for (unsigned i = 0; i < len; i++) {
      if (byte_enable_ptr[i] == 0xff)
        this->data[offset + i] = buf[i];
    }
    return latency;
  }
};

#include "platform/simple_memory.hpp"

#define DOCTEST_CONFIG_IMPLEMENT_WITH_MAIN
#include <doctest.h>

#include <cstdint>

#include <array>

TEST_CASE("simple_memory read write alias and bounds")
{
  SimpleMemory<32> mem{"mem", MemoryRegion{0x1000, 0x10ff},
                       MemoryRegion{0x2000, 0x20ff}};
  mem.latency = 3;

  {
    std::array<uint8_t, 4> write_data{0xde, 0xad, 0xbe, 0xef};
    tlm::tlm_generic_payload gp;
    gp.set_command(tlm::TLM_WRITE_COMMAND);
    gp.set_address(0x1000);
    gp.set_data_ptr(write_data.data());
    gp.set_data_length(write_data.size());
    gp.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
    sc_core::sc_time delay = sc_core::SC_ZERO_TIME;
    mem.b_transport(gp, delay);

    CHECK(gp.get_response_status() == tlm::TLM_OK_RESPONSE);
    CHECK(delay == sc_core::sc_time(3, sc_core::SC_NS));
    CHECK(mem.data[0] == 0xde);
    CHECK(mem.data[1] == 0xad);
    CHECK(mem.data[2] == 0xbe);
    CHECK(mem.data[3] == 0xef);
  }

  {
    std::array<uint8_t, 4> read_data{};
    tlm::tlm_generic_payload gp;
    gp.set_command(tlm::TLM_READ_COMMAND);
    gp.set_address(0x1000);
    gp.set_data_ptr(read_data.data());
    gp.set_data_length(read_data.size());
    gp.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
    sc_core::sc_time delay = sc_core::SC_ZERO_TIME;
    mem.b_transport(gp, delay);

    CHECK(gp.get_response_status() == tlm::TLM_OK_RESPONSE);
    CHECK(read_data == std::array<uint8_t, 4>{0xde, 0xad, 0xbe, 0xef});
  }

  {
    std::array<uint8_t, 4> alias_data{0x11, 0x22, 0x33, 0x44};
    tlm::tlm_generic_payload gp;
    gp.set_command(tlm::TLM_WRITE_COMMAND);
    gp.set_address(0x2000);
    gp.set_data_ptr(alias_data.data());
    gp.set_data_length(alias_data.size());
    gp.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
    sc_core::sc_time delay = sc_core::SC_ZERO_TIME;
    mem.b_transport(gp, delay);

    CHECK(gp.get_response_status() == tlm::TLM_OK_RESPONSE);
    CHECK(mem.data[0] == 0x11);
    CHECK(mem.data[1] == 0x22);
    CHECK(mem.data[2] == 0x33);
    CHECK(mem.data[3] == 0x44);
  }

  {
    std::array<uint8_t, 4> bytes{0, 0, 0, 0};
    tlm::tlm_generic_payload gp;
    gp.set_command(tlm::TLM_READ_COMMAND);
    gp.set_address(0x1234);
    gp.set_data_ptr(bytes.data());
    gp.set_data_length(bytes.size());
    gp.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
    sc_core::sc_time delay = sc_core::SC_ZERO_TIME;
    mem.b_transport(gp, delay);

    CHECK(gp.get_response_status() == tlm::TLM_ADDRESS_ERROR_RESPONSE);
    CHECK(delay == sc_core::sc_time(3, sc_core::SC_NS));
  }

  {
    std::array<uint8_t, 4> data{0xaa, 0xbb, 0xcc, 0xdd};
    std::array<uint8_t, 4> be{0xff, 0x00, 0xff, 0x00};
    tlm::tlm_generic_payload gp;
    gp.set_command(tlm::TLM_WRITE_COMMAND);
    gp.set_address(0x1004);
    gp.set_data_ptr(data.data());
    gp.set_data_length(data.size());
    gp.set_byte_enable_ptr(be.data());
    gp.set_byte_enable_length(be.size());
    gp.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
    sc_core::sc_time delay = sc_core::SC_ZERO_TIME;
    mem.b_transport(gp, delay);

    CHECK(gp.get_response_status() == tlm::TLM_OK_RESPONSE);
    CHECK(mem.data[4] == 0xaa);
    CHECK(mem.data[5] == 0x00);
    CHECK(mem.data[6] == 0xcc);
    CHECK(mem.data[7] == 0x00);
  }
}

TEST_CASE("simple_memory uses externally-supplied buffer when provided")
{
  std::array<uint8_t, 0x100> external{};
  external[0x10] = 0x42;

  SimpleMemory<32> mem{"mem", MemoryRegion{0x1000, 0x10ff},
                       MemoryRegion{SimpleMemory<32>::INVALID_ADDRESS,
                                    SimpleMemory<32>::INVALID_ADDRESS},
                       std::span<uint8_t>{external}};

  CHECK(mem.data.data() == external.data());

  {
    std::array<uint8_t, 1> read_data{};
    tlm::tlm_generic_payload gp;
    gp.set_command(tlm::TLM_READ_COMMAND);
    gp.set_address(0x1010);
    gp.set_data_ptr(read_data.data());
    gp.set_data_length(read_data.size());
    gp.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
    sc_core::sc_time delay = sc_core::SC_ZERO_TIME;
    mem.b_transport(gp, delay);

    CHECK(gp.get_response_status() == tlm::TLM_OK_RESPONSE);
    CHECK(read_data[0] == 0x42);
  }

  {
    std::array<uint8_t, 4> write_data{0xca, 0xfe, 0xba, 0xbe};
    tlm::tlm_generic_payload gp;
    gp.set_command(tlm::TLM_WRITE_COMMAND);
    gp.set_address(0x1020);
    gp.set_data_ptr(write_data.data());
    gp.set_data_length(write_data.size());
    gp.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
    sc_core::sc_time delay = sc_core::SC_ZERO_TIME;
    mem.b_transport(gp, delay);

    CHECK(gp.get_response_status() == tlm::TLM_OK_RESPONSE);
    CHECK(external[0x20] == 0xca);
    CHECK(external[0x21] == 0xfe);
    CHECK(external[0x22] == 0xba);
    CHECK(external[0x23] == 0xbe);
  }
}

TEST_CASE("simple_memory rejects external buffer smaller than region")
{
  std::array<uint8_t, 0x10> too_small{};
  CHECK_THROWS(
    SimpleMemory<32>("mem", MemoryRegion{0x1000, 0x10ff},
                     MemoryRegion{SimpleMemory<32>::INVALID_ADDRESS,
                                  SimpleMemory<32>::INVALID_ADDRESS},
                     std::span<uint8_t>{too_small}));
}

// MmapBacking + SimpleMemory glued together: writes via TLM land on disk,
// bytes pre-placed by an external owner are visible via TLM reads.

#include "platform/mmap_backing.hpp"
#include "platform/simple_memory.hpp"

#define DOCTEST_CONFIG_IMPLEMENT_WITH_MAIN
#include <doctest.h>

#include <fcntl.h>
#include <sys/mman.h>
#include <unistd.h>

#include <array>
#include <cstdio>
#include <cstdlib>
#include <filesystem>
#include <string>

namespace {
auto unique_tmp_path(const char* tag) -> std::string
{
  auto p = std::filesystem::temp_directory_path()
           / (std::string{"vsim_shared_mem_"} + tag + "_"
              + std::to_string(::getpid()));
  std::filesystem::remove(p);
  return p.string();
}
}  // namespace

TEST_CASE("write through SimpleMemory shows up on disk through MmapBacking")
{
  const auto path = unique_tmp_path("write");
  constexpr std::size_t kSize = 0x1000;
  constexpr uint64_t kBase = 0x1000;

  MmapBacking backing(path, kSize);
  SimpleMemory<32> mem{
    "mem", MemoryRegion{kBase, kBase + kSize - 1},
    MemoryRegion{SimpleMemory<32>::INVALID_ADDRESS,
                 SimpleMemory<32>::INVALID_ADDRESS},
    backing.span()};

  std::array<uint8_t, 4> bytes{0xde, 0xad, 0xbe, 0xef};
  tlm::tlm_generic_payload gp;
  gp.set_command(tlm::TLM_WRITE_COMMAND);
  gp.set_address(kBase + 0x100);
  gp.set_data_ptr(bytes.data());
  gp.set_data_length(bytes.size());
  gp.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
  sc_core::sc_time delay = sc_core::SC_ZERO_TIME;
  mem.b_transport(gp, delay);
  REQUIRE(gp.get_response_status() == tlm::TLM_OK_RESPONSE);

  // Independent reader: open the file fresh and mmap it.
  const int fd = ::open(path.c_str(), O_RDONLY);
  REQUIRE(fd >= 0);
  void* p = ::mmap(nullptr, kSize, PROT_READ, MAP_SHARED, fd, 0);
  REQUIRE(p != MAP_FAILED);
  auto* file_bytes = static_cast<const uint8_t*>(p);
  CHECK(file_bytes[0x100] == 0xde);
  CHECK(file_bytes[0x101] == 0xad);
  CHECK(file_bytes[0x102] == 0xbe);
  CHECK(file_bytes[0x103] == 0xef);
  ::munmap(p, kSize);
  ::close(fd);
  std::filesystem::remove(path);
}

TEST_CASE("bytes pre-placed in the file are read back through SimpleMemory")
{
  const auto path = unique_tmp_path("read");
  constexpr std::size_t kSize = 0x1000;
  constexpr uint64_t kBase = 0x1000;

  MmapBacking backing(path, kSize);
  // Outside writer (e.g. QEMU side) places known bytes via the same mapping.
  backing.span()[0x200] = 0xca;
  backing.span()[0x201] = 0xfe;

  SimpleMemory<32> mem{
    "mem", MemoryRegion{kBase, kBase + kSize - 1},
    MemoryRegion{SimpleMemory<32>::INVALID_ADDRESS,
                 SimpleMemory<32>::INVALID_ADDRESS},
    backing.span()};

  std::array<uint8_t, 2> bytes{};
  tlm::tlm_generic_payload gp;
  gp.set_command(tlm::TLM_READ_COMMAND);
  gp.set_address(kBase + 0x200);
  gp.set_data_ptr(bytes.data());
  gp.set_data_length(bytes.size());
  gp.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
  sc_core::sc_time delay = sc_core::SC_ZERO_TIME;
  mem.b_transport(gp, delay);
  REQUIRE(gp.get_response_status() == tlm::TLM_OK_RESPONSE);

  CHECK(bytes[0] == 0xca);
  CHECK(bytes[1] == 0xfe);
  std::filesystem::remove(path);
}

#include "platform/mmap_backing.hpp"

#define DOCTEST_CONFIG_IMPLEMENT_WITH_MAIN
#include <doctest.h>

#include <fcntl.h>
#include <sys/mman.h>
#include <sys/stat.h>
#include <unistd.h>

#include <cstdio>
#include <cstdlib>
#include <filesystem>
#include <string>

namespace {
auto unique_tmp_path(const char* tag) -> std::string
{
  auto p = std::filesystem::temp_directory_path()
           / (std::string{"vsim_mmap_"} + tag + "_"
              + std::to_string(::getpid()));
  std::filesystem::remove(p);
  return p.string();
}
}  // namespace

TEST_CASE("MmapBacking sizes the file and exposes the requested span")
{
  const auto path = unique_tmp_path("size");
  {
    MmapBacking backing(path, 0x4000);
    CHECK(backing.span().size() == 0x4000);

    struct stat st{};
    REQUIRE(::stat(path.c_str(), &st) == 0);
    CHECK(static_cast<size_t>(st.st_size) == 0x4000);
  }
  std::filesystem::remove(path);
}

TEST_CASE("Writes through the span are visible to a separate mmap of the file")
{
  const auto path = unique_tmp_path("share");
  MmapBacking backing(path, 0x1000);
  backing.span()[0x10] = 0xab;
  backing.span()[0x11] = 0xcd;

  const int fd = ::open(path.c_str(), O_RDONLY);
  REQUIRE(fd >= 0);
  void* p = ::mmap(nullptr, 0x1000, PROT_READ, MAP_SHARED, fd, 0);
  REQUIRE(p != MAP_FAILED);
  auto* bytes = static_cast<const uint8_t*>(p);
  CHECK(bytes[0x10] == 0xab);
  CHECK(bytes[0x11] == 0xcd);
  ::munmap(p, 0x1000);
  ::close(fd);
  std::filesystem::remove(path);
}

TEST_CASE("MmapBacking releases its mapping on destruction")
{
  const auto path = unique_tmp_path("close");
  {
    MmapBacking backing(path, 0x1000);
    backing.span()[0] = 0x77;
  }
  // After dtor, the file must still hold the byte; the mapping is gone.
  const int fd = ::open(path.c_str(), O_RDONLY);
  REQUIRE(fd >= 0);
  uint8_t b = 0;
  REQUIRE(::read(fd, &b, 1) == 1);
  CHECK(b == 0x77);
  ::close(fd);
  std::filesystem::remove(path);
}

