  for (int i = 0; i < 32; ++i) {
    src.gpr[i] = 0xCAFE0000ULL + i;
    src.fpr[i] = 0xF00D0000ULL + i;
  }
  src.mstatus = 0xa00040080ULL;
  src.mepc    = 0x80002000ULL;
  src.mtvec   = 0x80000000ULL;
  src.satp    = 0x8000000000080000ULL;
  src.vstart  = 0;
  src.vtype   = 0xc0;
  src.vl      = 4;
  src.vlenb   = 16;
  for (size_t i = 0; i < sizeof(src.vreg); ++i) src.vreg[i] = (uint8_t) i;

  alignas(hybrid_state_v1) unsigned char buf[sizeof(hybrid_state_v1)];
