// Reads and validates a hybrid_state_v1 from a file produced by the QEMU
// plugin. Validation is the boundary check before any in-process JTAG poke.

#include "hybrid/state_abi.h"
#include "hybrid/state_loader.hpp"

#define DOCTEST_CONFIG_IMPLEMENT_WITH_MAIN
#include <doctest.h>

#include <cstdio>
#include <cstring>
#include <filesystem>
#include <fstream>
#include <string>

namespace {
auto unique_tmp_path(const char* tag) -> std::string
{
  auto p = std::filesystem::temp_directory_path()
           / (std::string{"vsim_state_"} + tag + "_"
              + std::to_string(::getpid()));
  std::filesystem::remove(p);
  return p.string();
}

auto write_bytes(const std::string& path, const void* data, std::size_t n)
  -> void
{
  std::ofstream f(path, std::ios::binary | std::ios::trunc);
  f.write(static_cast<const char*>(data), static_cast<std::streamsize>(n));
}

auto good_state() -> hybrid_state_v1
{
  hybrid_state_v1 s{};
  s.magic = HYBRID_STATE_MAGIC;
  s.version = HYBRID_STATE_VERSION;
  s.flags = HYBRID_FLAG_RV64;
  s.hart_id = 0;
  s.pc = 0x80001000ULL;
  s.priv = 3;
  for (int i = 0; i < 32; ++i) s.gpr[i] = 0xA0000000ULL + i;
  return s;
}
}  // namespace

TEST_CASE("load_state returns the struct verbatim from a valid file")
{
  const auto path = unique_tmp_path("ok");
  const auto src = good_state();
  write_bytes(path, &src, sizeof(src));

  hybrid::HybridState loaded = hybrid::load_state(path);
  CHECK(loaded.magic == HYBRID_STATE_MAGIC);
  CHECK(loaded.version == HYBRID_STATE_VERSION);
  CHECK(loaded.pc == 0x80001000ULL);
  CHECK(loaded.priv == 3);
  for (int i = 0; i < 32; ++i) CHECK(loaded.gpr[i] == 0xA0000000ULL + i);
  std::filesystem::remove(path);
}

TEST_CASE("load_state rejects a missing file")
{
  const auto path = unique_tmp_path("missing");
  std::filesystem::remove(path);
  CHECK_THROWS(hybrid::load_state(path));
}

TEST_CASE("load_state rejects a wrong-magic file")
{
  const auto path = unique_tmp_path("magic");
  auto s = good_state();
  s.magic = 0xDEADBEEFu;
  write_bytes(path, &s, sizeof(s));
  CHECK_THROWS(hybrid::load_state(path));
  std::filesystem::remove(path);
}

TEST_CASE("load_state rejects a wrong-version file")
{
  const auto path = unique_tmp_path("version");
  auto s = good_state();
  s.version = HYBRID_STATE_VERSION + 1;
  write_bytes(path, &s, sizeof(s));
  CHECK_THROWS(hybrid::load_state(path));
  std::filesystem::remove(path);
}

TEST_CASE("load_state rejects a truncated file")
{
  const auto path = unique_tmp_path("short");
  auto s = good_state();
  write_bytes(path, &s, sizeof(s) - 16);
  CHECK_THROWS(hybrid::load_state(path));
  std::filesystem::remove(path);
}

