TEST_CASE("load_state returns the struct verbatim from a valid file")
{
  const auto path = unique_tmp_path("ok");
  const auto src = good_state();
  write_bytes(path, &src, sizeof(src));

  hybrid::HybridState loaded = hybrid::load_state(path);
  CHECK(loaded.magic == HYBRID_STATE_MAGIC);
  CHECK(loaded.version == HYBRID_STATE_VERSION);
  CHECK(loaded.pc == 0x80001000ULL);
  CHECK(loaded.priv == 3);
  for (int i = 0; i < 32; ++i) CHECK(loaded.gpr[i] == 0xA0000000ULL + i);
  std::filesystem::remove(path);
}

TEST_CASE("load_state rejects a missing file")
{
  const auto path = unique_tmp_path("missing");
  std::filesystem::remove(path);
  CHECK_THROWS(hybrid::load_state(path));
}

TEST_CASE("load_state rejects a wrong-magic file")
{
  const auto path = unique_tmp_path("magic");
  auto s = good_state();
  s.magic = 0xDEADBEEFu;
  write_bytes(path, &s, sizeof(s));
  CHECK_THROWS(hybrid::load_state(path));
  std::filesystem::remove(path);
}

TEST_CASE("load_state rejects a wrong-version file")
{
  const auto path = unique_tmp_path("version");
  auto s = good_state();
  s.version = HYBRID_STATE_VERSION + 1;
  write_bytes(path, &s, sizeof(s));
  CHECK_THROWS(hybrid::load_state(path));
  std::filesystem::remove(path);
}

TEST_CASE("load_state rejects a truncated file")
{
  const auto path = unique_tmp_path("short");
  auto s = good_state();
  write_bytes(path, &s, sizeof(s) - 16);
  CHECK_THROWS(hybrid::load_state(path));
  std::filesystem::remove(path);
}

