#include <cstring>
#include <filesystem>
#include <fstream>
#include <stdexcept>
#include <string>

namespace hybrid {

using HybridState = ::hybrid_state_v1;

inline auto load_state(const std::string& path) -> HybridState
{
  std::ifstream f(path, std::ios::binary);
  if (!f)
    throw std::runtime_error("hybrid::load_state: cannot open " + path);

  HybridState s{};
  f.read(reinterpret_cast<char*>(&s), sizeof(s));
  if (f.gcount() != static_cast<std::streamsize>(sizeof(s)))
    throw std::runtime_error("hybrid::load_state: short read on " + path);

  if (s.magic != HYBRID_STATE_MAGIC)
    throw std::runtime_error("hybrid::load_state: bad magic in " + path);
  if (s.version != HYBRID_STATE_VERSION)
    throw std::runtime_error("hybrid::load_state: unsupported version in "
                             + path);
  return s;
}

}  // namespace hybrid

