288	  void try_accept_socket()
289	  {
290	    if (this->socket) {
291	      spdlog::warn(
292	        "jtag_dtm: calling try_accept_socket() when a socket is already connected");
293	      return;
294	    }
295	
296	    auto socket = tcp::socket{asio::system_executor{}};
297	    auto ec = boost::system::error_code{};
298	    this->acceptor.accept(socket, ec);
299	    if (ec == asio::error::try_again)
300	      return;
301	
302	    if (ec)
303	      throw std::system_error{ec, "accept"};
304	
305	    socket.non_blocking(true);
306	    spdlog::info("jtag_dtm: accepted connection from {}:{}",
307	                 socket.remote_endpoint().address().to_string(),
308	                 socket.remote_endpoint().port());
309	    this->socket = std::move(socket);
310	  }
311	
312	  void tick()
313	  {
314	    if (this->socket) {
315	      if (this->recv_buf.empty()) {
316	        auto ec = boost::system::error_code{};
317	        const auto n =
318	          this->socket->read_some(asio::buffer(recv_buf_array), ec);
319	        if (ec == asio::error::try_again)
320	          return;
321	
322	        if (ec == asio::error::eof) {
323	          this->socket.reset();
324	          return;
325	        }
326	
327	        if (ec)
328	          throw std::system_error{ec, "read"};
329	
330	        this->recv_buf = std::span{recv_buf_array.data(), n};
331	        // spdlog::debug(
332	        //   "jtag_dtm: received: {}",
333	        //   std::string_view{this->recv_buf.data(), this->recv_buf.size()});
334	      }
335	
336	      auto write_buf = std::vector<char>{};
337	      while (!this->recv_buf.empty()) {
338	        const auto c = this->recv_buf.front();
339	        this->recv_buf = this->recv_buf.subspan<1>();
340	        switch (c) {
341	        case 'B':
342	          // spdlog::trace("jtag_dtm: blink on");
343	          break;
344	        case 'b':
345	          // spdlog::trace("jtag_dtm: blink off");
346	          break;
347	        case 'R':
348	          write_buf.push_back(this->tdo ? '1' : '0');
349	          break;
350	        case 'Q':
351	          spdlog::info("jtag_dtm: quit request received");
352	          this->socket.reset();
353	          break;
354	        case '0':
355	          set_tck_tms_tdi(false, false, false);
356	          break;
357	        case '1':
358	          set_tck_tms_tdi(false, false, true);
359	          break;
360	        case '2':
361	          set_tck_tms_tdi(false, true, false);
362	          break;
363	        case '3':
364	          set_tck_tms_tdi(false, true, true);
365	          break;
366	        case '4':
367	          set_tck_tms_tdi(true, false, false);
368	          break;
369	        case '5':
370	          set_tck_tms_tdi(true, false, true);
371	          break;
372	        case '6':
373	          set_tck_tms_tdi(true, true, false);
374	          break;
375	        case '7':
376	          set_tck_tms_tdi(true, true, true);
377	          break;
378	        case 'r':
379	          spdlog::info("jtag_dtm: reset request received");
380	          this->state = jtag_state::test_logic_reset;
381	          // TODO: reset
382	          break;
383	        default:
384	          spdlog::error("jtag_dtm: unimplemented request: {}", c);
385	          break;
386	        }
387	
388	        if (this->tck && this->state == jtag_state::run_test_idle)
389	          break;
390	      }
391	
392	      if (!write_buf.empty() && this->socket) {
393	        asio::write(this->socket.value(), asio::buffer(write_buf));
394	      }
395	    } else if (this->acceptor.is_open()) {
396	      try_accept_socket();
397	      return;
398	    }
399	  }
400	};
401	
402	#endif
403

