  CHECK(regno_gpr(31)    == 0x101F);
  CHECK(regno_fpr(0)     == 0x1020);
  CHECK(regno_fpr(31)    == 0x103F);
}

TEST_CASE("write 64-bit GPR x10 = 0x1000 with transfer set")
{
  // cmdtype=0 (zero), aarsize=3 (64-bit) at [22:20], transfer=1 at [17],
  // write=1 at [16], regno=0x100A in [15:0].
  const auto cmd = access_register_command(regno_gpr(10), AarSize::Bits64,
                                           /*write=*/true);
  CHECK(((cmd >> 24) & 0xff) == 0u);                // cmdtype = AccessRegister
  CHECK(((cmd >> 20) & 0x7) == uint32_t(AarSize::Bits64));
  CHECK(((cmd >> 17) & 0x1) == 1u);                 // transfer
  CHECK(((cmd >> 16) & 0x1) == 1u);                 // write
  CHECK((cmd & 0xffff)      == 0x100Au);            // regno
}

TEST_CASE("read 64-bit CSR mstatus has write=0")
{
  const auto mstatus = 0x300u;
  const auto cmd = access_register_command(regno_csr(mstatus), AarSize::Bits64,
                                           /*write=*/false);
  CHECK(((cmd >> 16) & 0x1) == 0u);
  CHECK((cmd & 0xffff)      == mstatus);
  CHECK(((cmd >> 17) & 0x1) == 1u);                 // transfer always 1
}

TEST_CASE("32-bit aarsize encodes as 2")
{
  const auto cmd =
    access_register_command(regno_gpr(1), AarSize::Bits32, /*write=*/true);
  CHECK(((cmd >> 20) & 0x7) == 2u);
}

TEST_CASE("postexec=true sets bit 18, otherwise unset")
{
  const auto with_post = access_register_command(
    regno_gpr(0), AarSize::Bits64, /*write=*/false, /*postexec=*/true);
  const auto without = access_register_command(
    regno_gpr(0), AarSize::Bits64, /*write=*/false, /*postexec=*/false);
  CHECK(((with_post >> 18) & 0x1) == 1u);
  CHECK(((without   >> 18) & 0x1) == 0u);
}

