// Recognises csrrw/csrrwi rd=0 to CSR 0x7C0, the magic handoff trigger. Pure
// bit pattern; the same predicate is consumed by the QEMU plugin (C) and by
// the vsim-side PC pre-scan (C++).

#include "hybrid/insn_match.h"

#define DOCTEST_CONFIG_IMPLEMENT_WITH_MAIN
#include <doctest.h>

#include <cstdint>

namespace {

// Build a SYSTEM-opcode csrrwi insn: csrrwi rd, csr, uimm.
auto encode_csrrwi(uint32_t rd, uint32_t csr, uint32_t uimm) -> uint32_t
{
  return (csr << 20) | (uimm << 15) | (0b101u << 12) | (rd << 7) | 0x73u;
}

// Build a SYSTEM-opcode csrrw insn: csrrw rd, csr, rs1.
auto encode_csrrw(uint32_t rd, uint32_t csr, uint32_t rs1) -> uint32_t
{
  return (csr << 20) | (rs1 << 15) | (0b001u << 12) | (rd << 7) | 0x73u;
}

}  // namespace

TEST_CASE("csrrwi rd=0, csr=0x7C0, uimm=0 (enter) matches and decodes uimm")
{
  const auto insn = encode_csrrwi(0, 0x7C0, 0);
  hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
  CHECK(hybrid_match_handoff_insn(insn, &kind));
  CHECK(kind == HYBRID_HANDOFF_ENTER);
}

TEST_CASE("csrrwi rd=0, csr=0x7C0, uimm=1 (exit) matches and decodes uimm")
{
  const auto insn = encode_csrrwi(0, 0x7C0, 1);
  hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
  CHECK(hybrid_match_handoff_insn(insn, &kind));
  CHECK(kind == HYBRID_HANDOFF_EXIT);
}

TEST_CASE("csrrw rd=0, csr=0x7C0 matches as runtime kind (rs1-borne)")
{
  const auto insn = encode_csrrw(0, 0x7C0, /*rs1=*/5);
  hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
  CHECK(hybrid_match_handoff_insn(insn, &kind));
  CHECK(kind == HYBRID_HANDOFF_RUNTIME);
}

TEST_CASE("a write to a different CSR does not match")
{
  const auto insn = encode_csrrwi(0, 0x7C1, 0);
  hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
  CHECK_FALSE(hybrid_match_handoff_insn(insn, &kind));
}

TEST_CASE("non-zero rd disqualifies (only csrw, not csrrw with rd!=0)")
{
  const auto insn = encode_csrrwi(/*rd=*/3, 0x7C0, 0);
  hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
  CHECK_FALSE(hybrid_match_handoff_insn(insn, &kind));
}

TEST_CASE("non-SYSTEM opcode does not match")
{
  const uint32_t addi = (1u << 20) | (0u << 15) | (0u << 12) | (0u << 7) | 0x13;
  hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
  CHECK_FALSE(hybrid_match_handoff_insn(addi, &kind));
}

TEST_CASE("csrrs (a read with set-bits) to 0x7C0 does not match")
{
  // funct3 = 010 = csrrs, not 001/101.
  const uint32_t insn =
    (0x7C0u << 20) | (0u << 15) | (0b010u << 12) | (0u << 7) | 0x73u;
  hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
  CHECK_FALSE(hybrid_match_handoff_insn(insn, &kind));
}

TEST_CASE("uimm=2 on csrwi is rejected (only 0 and 1 carry meaning)")
{
  const auto insn = encode_csrrwi(0, 0x7C0, 2);
  hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
  CHECK_FALSE(hybrid_match_handoff_insn(insn, &kind));
}

