struct transaction
{
  addr_type addr = 0;
  data_type data = 0;
  bool is_write = false;
  enum class phase
  {
    address,
    data,
    okay,
    error,
  } phase = phase::address;

  [[nodiscard]]
  auto is_busy() const -> bool
  {
    return this->phase == phase::address || this->phase == phase::data;
  }
};

