transaction txn = transaction{
  .addr = 0,
  .data = 0,
  .is_write = false,
  .phase = transaction::phase::okay,
};

auto read(const vlpin<AddrWidth> addr)
{
  // spdlog::trace("ahb::manager::read({:#x})", addr.to_uint64());
  assert(!this->txn.is_busy());
  this->txn = transaction{.addr = addr,
                          .data = 0,
                          .is_write = false,
