#include "utils/ahb.hpp"

#include <systemc>

#include <cstdint>
#include <stdexcept>

namespace hybrid {

// Drives the platform's DMI AHB manager synchronously. Each read/write blocks
// (advancing SystemC time) until the transaction reaches okay or error.
template<std::size_t AddrWidth, std::size_t DataWidth>
class SystemCDmiBus final : public DmiBus
{
public:
  using ahb_manager = ahb::manager<AddrWidth, DataWidth>;

  SystemCDmiBus(ahb_manager& ahb, const sc_core::sc_time& cycle)
      : ahb_{ahb}, cycle_{cycle}
  {}

  void write(uint8_t reg, uint32_t value) override
  {
    static_cast<void>(ahb_.write(typename ahb_manager::addr_type(reg << 2),
                                 typename ahb_manager::data_type(value)));
    drain();
  }

  auto read(uint8_t reg) -> uint32_t override
  {
    ahb_.read(typename ahb_manager::addr_type(reg << 2));
    drain();
    return uint32_t(ahb_.txn.data.to_uint64());
  }

private:
  void drain()
  {
    while (ahb_.txn.is_busy()) sc_core::sc_start(cycle_);
    if (ahb_.txn.phase == ahb_manager::transaction::phase::error)
      throw std::runtime_error("SystemCDmiBus: DMI transaction error");
  }

  ahb_manager& ahb_;
  sc_core::sc_time cycle_;
};

}  // namespace hybrid

